/* Return the largest sum of any contiguous subarray in the vector x.
   Complexity: O(n²) – parallelised over the outer loop.
   The function signature is unchanged.
*/

int maximumSubarray(std::vector<int> const& x) {
    int largestSum = std::numeric_limits<int>::lowest();
    const size_t n = x.size();

    // Parallelise the outer loop; each thread keeps a local maximum.
    #pragma omp parallel
    {
        int localMax = std::numeric_limits<int>::lowest();
        #pragma omp for nowait
        for (int i = 0; i < static_cast<int>(n); ++i) {
            int currSum = 0;
            for (int j = i; j < static_cast<int>(n); ++j) {
                currSum += x[j];
                if (currSum > localMax) { localMax = currSum; }
            }
        }
        #pragma omp critical
        if (localMax > largestSum) { largestSum = localMax; }
    }

    return largestSum;
}
