/* Return the value of the smallest odd number in the vector x.
   If no odd numbers exist, return std::numeric_limits<int>::max().
*/
int smallestOdd(std::vector<int> const& x) {
    const int n = static_cast<int>(x.size());
    if (n == 0) return std::numeric_limits<int>::max();

    int global_min = std::numeric_limits<int>::max();

    // Parallel reduction with a custom local bucket.
    #pragma omp parallel
    {
        int local_min = std::numeric_limits<int>::max();

        #pragma omp for nowait
        for (int i = 0; i < n; ++i) {
            int v = x[i];
            if ((v & 1) && v < local_min) // v is odd
                local_min = v;
        }

        // Merge local minima into global_min
        #pragma omp atomic compare
        for (;;) {
            int current = global_min;
            if (local_min >= current) break;
            if (__sync_bool_compare_and_swap(&global_min, current, local_min))
                break;
        }
    }

    return global_min;
}
