/*
 * Count for each lowercase letter the number of strings in `s`
 * that start with that letter.
 *
 * Results are stored in `bins[0] = 'a', bins[1] = 'b', … , bins[25] = 'z'`.
 *
 * The implementation uses OpenMP parallelism and a SIMD‑friendly
 * reduction on the 26‑element array.  The exact behavior of the
 * serial reference implementation is preserved.
 */
inline void firstLetterCounts(const std::vector<std::string>& s,
                              std::array<std::size_t, 26>& bins)
{
    // Zero‑initialize the output array
    bins.fill(0);

    /* Parallel loop over the input strings.
     *
     * - `schedule(static)` gives a roughly even split of iterations
     *   between threads without runtime overhead of dynamic scheduling.
     * - `reduction(+:bins[:26])` performs a private copy of the
     *   26‑element array for each thread and sums them at the end,
     *   which is very efficient for such a small fixed size.
     */
#pragma omp parallel for schedule(static) reduction(+:bins[:26])
    for (std::size_t i = 0; i < s.size(); ++i)
    {
        const unsigned char c = static_cast<unsigned char>(s[i][0]);
        const int index = c - 'a';
        /* index is guaranteed to be in [0,25] because input strings
         * only contain lowercase letters.
         */
        bins[index] += 1;
    }
}
