16_graph_largest_component:
```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cstdint>

/* Return the number of vertices in the largest component of the graph
   defined by the adjacency matrix A.  A is an NxN adjacency matrix
   stored in row‑major order.  */
int largestComponent(std::vector<int> const& A, size_t N)
{
    // Use a byte per vertex for visited flag (0 == unvisited, 1 == visited)
    std::vector<std::uint8_t> visited(N, 0);
    int maxSize = 0;

    // Pointer to the underlying data for faster indexing
    const int* mat = A.data();

    // Helper stack for iterative DFS
    std::vector<int> stack;
    stack.reserve(N);

    for (int start = 0; start < static_cast<int>(N); ++start)
    {
        if (visited[start]) continue;

        int compSize = 0;
        stack.clear();
        stack.push_back(start);
        visited[start] = 1;

        while (!stack.empty())
        {
            int v = stack.back();
            stack.pop_back();
            ++compSize;

            // Scan the row for neighbours
            const int* row = mat + v * static_cast<int>(N);
            for (int nei = 0; nei < static_cast<int>(N); ++nei)
            {
                if (row[nei] && !visited[nei])
                {
                    visited[nei] = 1;
                    stack.push_back(nei);
                }
            }
        }

        if (compSize > maxSize) maxSize = compSize;
    }

    return maxSize;
}
