```cpp
// optimized version of shortestPathLength
// ------------------------------------------------------------
// Use a flat queue implementation to avoid pair allocation,
// use a single-byte visited array, and employ a fast
// single-pass adjacency scan. The logic is identical to
// the original but with significant performance gains.
//
// ------------------------------------------------------------
#pragma once
#include <vector>
#include <limits>
#include <cstring>   // for memset

inline int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {
    // Fast visited array – 1 byte per vertex
    std::vector<uint8_t> visited(N, 0);

    // Flat queue (array of vertices)
    std::vector<int> q(N);
    size_t head = 0, tail = 0;
    const size_t stride = N;               // rows are contiguous

    visited[source] = 1;
    q[tail++] = source;                    // distance 0 is implicit
    const int *data = A.data();            // raw pointer for speed

    int dist = 0;                          // current layer distance
    while (head < tail) {
        // Process current layer (all nodes that were added in the previous loop)
        size_t layerEnd = tail;
        while (head < layerEnd) {
            int cur = q[head++];
            if (cur == dest) {
                return dist;
            }
            const int *row = data + cur * stride;
            for (size_t i = 0; i < N; ++i) {
                if (row[i] && !visited[i]) {
                    visited[i] = 1;
                    q[tail++] = static_cast<int>(i);
                }
            }
        }
        ++dist;                            // next layer distance
    }
    return std::numeric_limits<int>::max();   // unreachable (should not happen)
}
