#pragma once
#include <array>
#include <vector>
#include <omp.h>

/* Count the number of doubles in the vector `x` that have a fractional part
   in [0, 0.25), [0.25, 0.5), [0.5, 0.75), and [0.75, 1). Store the counts in
   `bins`. The function preserves the exact semantics of the original
   implementation while exploiting thread‑parallelism and cache locality. */
inline void countQuartiles(std::vector<double> const& x, std::array<std::size_t, 4> &bins)
{
    // local thread‐private counters to avoid false sharing
    constexpr int BINS = 4;
    std::size_t local[BINS][omp_get_max_threads()] = {};

    const std::size_t n = x.size();
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t chunk = (n + omp_get_num_threads() - 1) / omp_get_num_threads();
        const std::size_t beg = tid * chunk;
        const std::size_t end = std::min(beg + chunk, n);

        for (std::size_t i = beg; i < end; ++i) {
            double const v = x[i];
            double const frac = v - std::floor(v);   // guarantees [0,1)
            if (frac < 0.25)          ++local[0][tid];
            else if (frac < 0.5)      ++local[1][tid];
            else if (frac < 0.75)     ++local[2][tid];
            else                      ++local[3][tid];
        }
    }

    // accumulate per‑thread results into the output array
    for (int b = 0; b < BINS; ++b) {
        std::size_t sum = 0;
        for (int t = 0; t < omp_get_max_threads(); ++t)
            sum += local[b][t];
        bins[b] = sum;
    }
}
