#pragma once
#include <vector>
#include <unordered_map>
#include <utility>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Compute Y = A * X.
   A : M × K COO sparse matrix
   X : K × N COO sparse matrix
   Y : dense M × N matrix, row‑major
*/
void spmm(const std::vector<COOElement> &A,
          const std::vector<COOElement> &X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
    /* Allocate output matrix */
    Y.assign(M * N, 0.0);

    /* Build an index of X entries by source row for fast look‑up */
    std::vector<std::vector<std::pair<size_t,double>>> X_rows(K);
    for (const auto &e : X)
        X_rows[e.row].emplace_back(e.column, e.value);

    /* Parallel over the non‑zeros of A.
       Atomic updates to Y are used to avoid write conflicts.
     */
#pragma omp parallel for schedule(static)
    for (intptr_t ai = 0; ai < static_cast<intptr_t>(A.size()); ++ai)
    {
        const auto &a = A[ai];
        const auto &targets = X_rows[a.column];
        if (targets.empty()) continue;

        const size_t base = a.row * N;          // row offset in Y
        const double av   = a.value;
        for (const auto &t : targets)
        {
            const size_t col  = t.first;
            const double xv  = t.second;
            const size_t idx = base + col;
#pragma omp atomic
            Y[idx] += av * xv;
        }
    }
}
