/*
  Count the number of entries in x that fall into the ten equal‑width bins
  [0,10), [10,20), …, [90,100].  The input values are doubles in the
  range 0…100 inclusive.  The result is written into `bins`, whose
  length is 10.  The original implementation was serial; this
  replacement uses OpenMP to split the work across the available
  threads while preserving the exact semantics.

  The algorithm:
    1.  Zero the output array.
    2.  Iterate over the input in parallel, determining the bin index
        by integer truncation (`static_cast<int>(x[i]) / 10`).
    3.  Use an array of atomic counters for each bin so that no
        data‑races occur when multiple threads update the same bin.

  Because the bin values are always in [0,10], the bin index is always
  a valid array index.  The function is thread‑safe and will return
  the same exact results as the original serial implementation.
*/
inline void binsBy10Count(const std::vector<double> &x,
                          std::array<std::size_t, 10> &bins) noexcept
{
    // Reset bins to zero; ensure this is done once per call.
    std::fill(bins.begin(), bins.end(), 0);

    // Use a local reduction array to avoid atomic ops.
    // Each thread keeps its own partial counts and they are merged
    // after the parallel loop.
#pragma omp parallel
    {
        std::array<std::size_t, 10> local = {};  // zero‑init in each thread

#pragma omp for nowait
        for (std::size_t i = 0; i < x.size(); ++i)
        {
            // Casting to int truncates toward zero – valid because values are
            // non‑negative and no overrun can occur.
            const std::size_t bin = static_cast<std::size_t>(x[i]) / 10;
            ++local[bin];
        }

        // Combine the local counters into the global result.
#pragma omp atomic update
        for (std::size_t b = 0; b < 10; ++b)
            bins[b] += local[b];
    }
}
