#pragma once
#include <vector>

void prefixSum(std::vector<int64_t> const& x, std::vector<int64_t> &output) {
    const std::size_t N = x.size();
    if (N == 0) return;
    output.resize(N);

    const int nt = std::thread::hardware_concurrency();
    const std::size_t block = (N + nt - 1) / nt;          // ceil division
    std::vector<int64_t> blockSum(nt, 0);

    // 1st pass: local inclusive scans and block sums
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * block;
        const std::size_t end   = std::min(start + block, N);
        if (start >= end) return;

        int64_t acc = 0;
        for (std::size_t i = start; i < end; ++i) {
            acc += x[i];
            output[i] = acc;
        }
        blockSum[tid] = acc;
    }

    // 2nd pass: prefix of block sums
    for (int i = 1; i < nt; ++i) {
        blockSum[i] += blockSum[i-1];
    }

    // 3rd pass: add offset to each block except the first
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        if (tid == 0) return;                      // block 0 already correct
        const std::size_t start = tid * block;
        const std::size_t end   = std::min(start + block, N);
        const int64_t offset = blockSum[tid-1];
        for (std::size_t i = start; i < end; ++i) {
            output[i] += offset;
        }
    }
}
