#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// ---------------------------------------------------------------
// Optimised DFT implementation
// ---------------------------------------------------------------
void dft(const std::vector<double> &x,
         std::vector<std::complex<double>> &output)
{
    const std::size_t N = x.size();
    output.assign(N, std::complex<double>(0.0, 0.0));

    // Pre‑compute the angular factor table: cos(2πnk/N) and sin(2πnk/N).
    // We keep two separate flat arrays to take advantage of spatial locality.
    std::vector<double> cos_tab(N * N);
    std::vector<double> sin_tab(N * N);

    const double two_pi_over_N = 2.0 * M_PI / static_cast<double>(N);

    for (std::size_t k = 0; k < N; ++k)
    {
        const double k_val = static_cast<double>(k);
        const std::size_t base = k * N;
        for (std::size_t n = 0; n < N; ++n)
        {
            const double angle = two_pi_over_N * static_cast<double>(n) * k_val;
            cos_tab[base + n] = std::cos(angle);
            sin_tab[base + n] = std::sin(angle);
        }
    }

    // Parallel compute each output coefficient.
    // We avoid the inner temp object allocation by computing the real
    // and imaginary parts separately.
#pragma omp parallel for schedule(static)
    for (int k = 0; k < static_cast<int>(N); ++k)
    {
        const std::size_t base = static_cast<std::size_t>(k) * N;
        double real_sum  = 0.0;
        double imag_sum  = 0.0;

        const double *const x_ptr = x.data();
        const double *const cos_ptr = &cos_tab[base];
        const double *const sin_ptr = &sin_tab[base];

        for (std::size_t n = 0; n < N; ++n)
        {
            const double val = x_ptr[n];
            real_sum += val * cos_ptr[n];
            imag_sum -= val * sin_ptr[n];  // note the minus sign for the imaginary part
        }

        output[static_cast<std::size_t>(k)] = std::complex<double>(real_sum, imag_sum);
    }
}
