/* Count the number of connected components in the undirected graph defined by
 * the adjacency matrix A.
 * A is an NxN adjacency matrix stored in row-major order.
 * Returns the exact same result as the original implementation.
 */
inline int componentCount(const std::vector<int>& A, size_t N) {
    // Use a byte per vertex to avoid `std::vector<bool>` specialisation overhead.
    std::vector<uint8_t> visited(N, 0);
    int componentCnt = 0;
    std::vector<int> stack;
    stack.reserve(N);                 // avoid reallocations

    for (size_t start = 0; start < N; ++start) {
        if (visited[start]) continue;

        // New component found.
        ++componentCnt;
        visited[start] = 1;
        stack.clear();
        stack.push_back(static_cast<int>(start));

        while (!stack.empty()) {
            const int u = stack.back();
            stack.pop_back();
            const size_t base = static_cast<size_t>(u) * N;

            // Scan the row for neighbours.
            for (size_t v = 0; v < N; ++v) {
                if (A[base + v] & 1 && !visited[v]) {
                    visited[v] = 1;
                    stack.push_back(static_cast<int>(v));
                }
            }
        }
    }
    return componentCnt;
}
