/* Compute one iteration of a 3‑point 1‑D Jacobi stencil.
   The function is fully parallelised with OpenMP and written to minimise
   branch mis‑predictions. */
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output)
{
    const std::size_t n = input.size();
    if (n == 0) return;

    const double inv3 = 1.0/3.0;
    const double *restrict in  = input.data();
              double *restrict out = output.data();

    /* Handle first element separately – no left neighbour */
    out[0] = (in[0] + in[1]) * inv3;

    /* Main loop – no bounds checks inside */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < n; ++i) {
        const double sum = in[i-1] + in[i] + in[i+1];
        out[i] = sum * inv3;
    }

    /* Handle last element separately – no right neighbour */
    out[n-1] = (in[n-2] + in[n-1]) * inv3;
}
