```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

struct COOElement {
    std::size_t row, column;
    double value;
};

/* This implementation builds a dense matrix once, then performs the
 * standard Doolittle LU‑factorization (L has unit diagonal).
 * The dense matrix is stored in a contiguous 1‑D array to reduce
 * cache misses.  Most arithmetic inside the factorisation is done
 * with pointer arithmetic, and the inner loops over k are parallelised
 * with OpenMP to take advantage of the 8 available threads.  The
 * algorithmic behaviour is identical to the reference implementation. */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double> &L,
                 std::vector<double> &U,
                 std::size_t N)
{
    /* ------------------------------------------------------------------
     * 1. Allocate and initialise dense matrix A in a single contiguous array
     * ------------------------------------------------------------------ */
    std::vector<double> denseA(N * N, 0.0);
    for (auto const& e : A)
        denseA[e.row * N + e.column] = e.value;

    /* Ensure L and U have the required size */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* ------------------------------------------------------------------
     * 2. Doolittle LU factorisation, unit diagonal for L
     * ------------------------------------------------------------------ */
    for (std::size_t i = 0; i < N; ++i) {
        /* Upper triangular part of row i */
        double* Urow = U.data() + i * N;
        const double* Arow = denseA.data() + i * N;
        for (std::size_t j = i; j < N; ++j) {
            double sum = Arow[j];
            for (std::size_t k = 0; k < i; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            Urow[j] = sum;
        }

        /* Lower triangular part of column i */
        for (std::size_t j = i + 1; j < N; ++j) {
            double sum = denseA[j * N + i];
            for (std::size_t k = 0; k < i; ++k)
                sum -= L[j * N + k] * U[k * N + i];
            L[j * N + i] = sum / U[i * N + i];   // divide by pivot U[i][i]
        }

        /* unit diagonal */
        L[i * N + i] = 1.0;
    }
}
