/* Return the distance between the closest two elements in the vector x.
   Example:
   input: [7, 3, 9, 12, 31, 1]
   output: 2
*/
double closestPair(std::vector<double> const& x) {
    // The vector needs to have at least two elements
    if (x.size() < 2) {
        return 0.0;
    }

    // Make a copy so we don't modify the original vector
    std::vector<double> sorted(x);
    std::sort(std::execution::par, sorted.begin(), sorted.end());

    // Find the smallest difference between adjacent sorted values
    double minDist = std::numeric_limits<double>::max();
    for (size_t i = 1; i < sorted.size(); ++i) {
        double const diff = sorted[i] - sorted[i - 1];
        if (diff < minDist) {
            minDist = diff;
            // early exit if the distance is zero
            if (minDist == 0.0) {
                break;
            }
        }
    }
    return minDist;
}
