    if (n < 3) return 0.0;

    double global_min = std::numeric_limits<double>::max();

    // Parallel brute‑force over all unordered triples
    #pragma omp parallel for schedule(static) reduction(min : global_min)
    for (size_t i = 0; i < n - 2; ++i) {
        const Point& pi = points[i];
        for (size_t j = i + 1; j < n - 1; ++j) {
            const Point& pj = points[j];
            for (size_t k = j + 1; k < n; ++k) {
                double area = tri_area(pi, pj, points[k]);
                if (area < global_min) global_min = area;
                // an area of 0 cannot be beaten
                if (global_min == 0.0) goto done;
            }
        }
    }
