   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
*/
inline void pixelCounts(const std::vector<int>& image, std::array<size_t, 256>& bins)
{
    const size_t n   = image.size();
    const int    thr = omp_get_max_threads();

    // Allocate per‑thread private histograms
    std::vector<std::array<size_t,256>> localBins(thr);
    for (int t = 0; t < thr; ++t)
        std::fill(localBins[t].begin(), localBins[t].end(), 0);

    const size_t chunk = (n + thr - 1) / thr;   // size of sub‑range per thread

#pragma omp parallel
    {
        const int    tid   = omp_get_thread_num();
        const size_t start = tid * chunk;
        const size_t end   = std::min(start + chunk, n);
        auto&        hist  = localBins[tid];

        // Work over the assigned sub‑range
        for (size_t i = start; i < end; ++i)
            ++hist[static_cast<unsigned char>(image[i])];
    }

    // Merge per‑thread histograms into the final result
    std::fill(bins.begin(), bins.end(), 0);
    for (int t = 0; t < thr; ++t)
        for (int i = 0; i < 256; ++i)
            bins[i] += localBins[t][i];
