#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:

   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
inline void solveLinearSystem(
    const std::vector<COOElement>& A,
    const std::vector<double>& b,
    std::vector<double>& x,
    size_t N)
{
    // 1. Create a densely stored matrix as a flat N×N array
    std::vector<double> M(N * N, 0.0);

    // parallel fill of the matrix
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const auto& el = A[idx];
        M[el.row * N + el.column] = el.value;
    }

    // 2. Copy RHS
    std::vector<double> rhs = b;

    // 3. Gaussian elimination with partial pivoting
    for (size_t i = 0; i < N; ++i) {
        // Pivot search
        size_t maxRow = i;
        double maxVal = std::abs(M[i * N + i]);
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(M[k * N + i]);
            if (val > maxVal) {
                maxVal = val;
                maxRow = k;
            }
        }
        // Swap rows in M and rhs
        if (maxRow != i) {
            for (size_t c = 0; c < N; ++c) {
                std::swap(M[i * N + c], M[maxRow * N + c]);
            }
            std::swap(rhs[i], rhs[maxRow]);
        }

        // Avoid division by zero
        double pivot = M[i * N + i];
        // Eliminate rows below pivot
        #pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -M[k * N + i] / pivot;
            // Update the row
            for (size_t j = i; j < N; ++j) {
                if (i == j)
                    M[k * N + j] = 0.0;
                else
                    M[k * N + j] += factor * M[i * N + j];
            }
            rhs[k] += factor * rhs[i];
        }
    }

    // 4. Back substitution
    x.resize(N);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = rhs[i];
        for (size_t j = i + 1; j < N; ++j) {
            sum -= M[i * N + j] * x[j];
        }
        x[i] = sum / M[i * N + i];
    }
}
