#include <execution>   // Parallel algorithms (C++17)

struct Point {
    double x, y;
};

/* Monotone-chain convex hull
 * Maintains exact semantics of the original implementation.
 */
inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(std::vector<Point> const& points, std::vector<Point>& hull) {
    size_t n = points.size();
    if (n < 3) {  // trivial cases
        hull = points;
        return;
    }

    // Make a copy that will be sorted
    std::vector<Point> sorted(points);
    // Parallel sort (if data is large, this gives measurable speedup)
    std::sort(std::execution::par_unseq, sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // Reserve space for the hull (max 2n points)
    std::vector<Point> ans;
    ans.reserve(2 * n);

    // Lower hull
    for (size_t i = 0; i < n; ++i) {
        while (ans.size() >= 2 &&
               cross(ans[ans.size() - 2], ans[ans.size() - 1], sorted[i]) <= 0)
            ans.pop_back();
        ans.push_back(sorted[i]);
    }

    // Upper hull
    size_t lower_size = ans.size();  // mark the boundary
    for (size_t i = n - 1; i > 0; --i) {
        while (ans.size() > lower_size &&
               cross(ans[ans.size() - 2], ans[ans.size() - 1], sorted[i - 1]) <= 0)
            ans.pop_back();
        ans.push_back(sorted[i - 1]);
    }

    // Remove the duplicate start/end point
    ans.pop_back();

    hull.swap(ans);  // move result without copying
}
