/*
 * Set every cell's value to 1 if it has exactly one neighbor that's a 1.
 * Otherwise set it to 0.
 * input and output are NxN grids of ints in row‑major order.
 */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     size_t N)
{
    const size_t total = N * N;

    /* Parallelize over all cells */
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < total; ++idx)
    {
        size_t i = idx / N;
        size_t j = idx % N;

        int sum = 0;
        /* Check top neighbour */
        if (i > 0)
            sum += input[(i - 1) * N + j];
        /* Check bottom neighbour */
        if (i + 1 < N)
            sum += input[(i + 1) * N + j];
        /* Check left neighbour */
        if (j > 0)
            sum += input[i * N + j - 1];
        /* Check right neighbour */
        if (j + 1 < N)
            sum += input[i * N + j + 1];

        output[idx] = (sum == 1) ? 1 : 0;
    }
}
