#include <omp.h>

static inline void bit_reverse(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t rev = 0, n = i, shift = logN;
        while (n) { rev = (rev << 1) | (n & 1); n >>= 1; }
        rev <<= (std::numeric_limits<std::size_t>::digits - logN);
        rev >>= (std::numeric_limits<std::size_t>::digits - logN);
        if (rev > i) {
            std::swap(x[i], x[rev]);
        }
    }
}

void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));

    // Bit‑reverse order
    bit_reverse(x);

    // Iterative radix‑2 Cooley‑Tukey
    for (std::size_t s = 1; s <= logN; ++s) {
        const std::size_t m = 1u << s;          // section size
        const std::size_t m2 = m >> 1;          // half section
        const double theta = -2.0 * M_PI / static_cast<double>(m);
        const double c = std::cos(theta);
        const double s_ = std::sin(theta);

        std::complex<double> w(1.0, 0.0);
        std::complex<double> w_m(c, s_);

        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m) {
            std::complex<double> tau(1.0, 0.0);
            for (std::size_t j = 0; j < m2; ++j) {
                const std::size_t a = k + j;
                const std::size_t b = a + m2;
                std::complex<double> t = x[b] * tau;
                x[b] = x[a] - t;
                x[a] += t;
                tau *= w_m;
            }
        }
    }

    // Conjugate result
    #pragma omp parallel for schedule(static)
