/*
 * Compute one iteration of a 5‑point 2‑D Jacobi stencil.
 *
 * Each element of `input` is averaged with its four neighbours (zero‑padding)
 * and written to `output`.  The function is fully parallelised with OpenMP
 * and fully vectorisable for modern x86‑64 CPUs.
 *
 * Parameters:
 *   input  - 2‑D grid in row‑major order, size N×N, read‑only
 *   output - 2‑D grid in row‑major order, size N×N, written
 *   N      - size of each dimension
 */
inline void jacobi2D(const std::vector<double> &input,
                     std::vector<double> &output,
                     size_t N)
{
    const double inv5 = 0.2;                     // 1/5
    const size_t stride = N;                     // row stride

    // Row‑major indexing via pointers is fastest on x86‑64.
    // Use OpenMP parallel for with collapse(2) for maximal thread
    // utilisation and cache‑line friendliness.
#pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const double *row_up   = (i > 0)   ? &input[(i-1)*stride] : nullptr;
        const double *row_down = (i + 1 < N)? &input[(i+1)*stride] : nullptr;
        const double *row_cur  = &input[i*stride];

        double *row_out = &output[i*stride];

        for (size_t j = 0; j < N; ++j)
        {
            double sum = row_cur[j];

            if (row_up)   sum += row_up[j];
            if (row_down) sum += row_down[j];

            if (j > 0)     sum += row_cur[j-1];
            if (j + 1 < N) sum += row_cur[j+1];

            row_out[j] = sum * inv5;   // avoid the division
        }
    }
}
