/* For each value in the vector x compute its index in the sorted vector.
   Store the results in `ranks_`.
   ===
   Approach:
      1. Create a list of indices.
      2. Std::sort the indices using the values from `x`.
      3. Build the rank array.
   The implementation is very small, but we also take advantage of OpenMP
   when available for the final assignment step – this is the only part that
   can benefit from multiple threads.
*/
inline void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    // Allocate index list
    std::vector<size_t> indices(x.size());
    std::iota(indices.begin(), indices.end(), 0);

    // Sort indices by corresponding values
    std::sort(indices.begin(), indices.end(),
              [&x](size_t a, size_t b) { return x[a] < x[b]; });

    // Write ranks – can be done in parallel
#ifdef _OPENMP
#pragma omp parallel for schedule(static)
#endif
    for (size_t i = 0; i < indices.size(); ++i) {
        ranks_[indices[i]] = i;
    }
}
