#pragma once
#include <vector>
#include <algorithm>
#include <cmath>

struct Point {
    double x, y;
};

static inline double cross(const Point& a, const Point& b, const Point& c) noexcept
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

static inline double dist(const Point& a, const Point& b) noexcept
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Return the perimeter of the smallest convex polygon that contains all
   the points in the vector points.
   Input: points of type std::vector<Point>
   Output: perimeter as double
*/
double convexHullPerimeter(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Copy and sort points lexicographically
    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    // Convex hull – monotone chain
    std::vector<Point> hull;
    hull.reserve(2 * n);

    // Lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], pts[i]) <= 0)
            hull.pop_back();
        hull.push_back(pts[i]);
    }

    // Upper hull
    std::size_t t = hull.size() + 1;
    for (std::size_t i = n; i-- > 1;) {   // i from n-1 down to 1
        while (hull.size() >= t &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], pts[i - 1]) <= 0)
            hull.pop_back();
        hull.push_back(pts[i - 1]);
    }

    // Last point is same as first, remove duplicate
    hull.pop_back();

    // Perimeter
    double perim = 0.0;
    const std::size_t m = hull.size();
    for (std::size_t i = 0; i < m; ++i)
        perim += dist(hull[i], hull[(i + 1) % m]);

    return perim;
}
