#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/* Iterative radix‑2 Cooley‑Tukey FFT.  The function preserves the
   exact behaviour of the reference implementation: an in‑place FFT
   that works for any power‑of‑two N.
   It is parallelised with OpenMP on the outermost butterfly stages. */
void fft(std::vector<std::complex<double>> const& x,
         std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;

    /* Bit‑reverse permutation */
    const unsigned int logN = static_cast<unsigned int>(std::log2(N));
    if (N > 1) {
        for (std::size_t i = 0; i < N; ++i) {
            std::size_t j = i;
            j = (((j & 0xaaaaaaaaU) >> 1) | ((j & 0x55555555U) << 1));
            j = (((j & 0xccccccccU) >> 2) | ((j & 0x33333333U) << 2));
            j = (((j & 0xf0f0f0f0U) >> 4) | ((j & 0x0f0f0f0fU) << 4));
            j = (((j & 0xff00ff00U) >> 8) | ((j & 0x00ff00ffU) << 8));
            j = ((j >> 16) | (j << 16));
            j >>= (32 - logN);
            if (j > i) std::swap(output[i], output[j]);
        }
    }

    /* Pre‑compute twiddle factors for the whole transform */
    std::vector<std::complex<double>> twiddles(N/2);
    const double two_pi = 2.0 * M_PI;
    for (std::size_t k = 0; k < N/2; ++k) {
        double angle = -two_pi * k / N;
        twiddles[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    /* Butterfly stages */
    std::size_t step = 1;
    for (unsigned int stage = 0; stage < logN; ++stage, step <<= 1) {
        const std::size_t jump = step << 1;
#pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += jump) {
            const std::size_t att = i + step;
            for (std::size_t j = i; j < att; ++j) {
                const std::size_t idx = (j - i) * N / jump;
                std::complex<double> t = output[j + step] * twiddles[idx];
                output[j + step] = output[j] - t;
                output[j] += t;
            }
        }
    }
}
