inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       std::size_t N)
{
    // Parallelise row/column loops with OpenMP.  The loop is collapsed
    // so that work is split evenly among the 8 cores.
    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        const std::size_t row = i * N;
        const std::size_t prevRow = (i > 0) ? (i - 1) * N : N;   // sentinel
        const std::size_t nextRow = (i + 1 < N) ? (i + 1) * N : N;

        for (std::size_t j = 0; j < N; ++j)
        {
            int sum = 0;

            // vertical neighbours
            if (i > 0)       sum += input[prevRow + j];
            if (i + 1 < N)   sum += input[nextRow + j];

            // horizontal neighbours
            if (j > 0)       sum += input[row + j - 1];
            if (j + 1 < N)   sum += input[row + j + 1];

            // diagonal neighbours
            if (i > 0 && j > 0)           sum += input[prevRow + j - 1];
            if (i > 0 && j + 1 < N)       sum += input[prevRow + j + 1];
            if (i + 1 < N && j > 0)       sum += input[nextRow + j - 1];
            if (i + 1 < N && j + 1 < N)   sum += input[nextRow + j + 1];

            const int cell = input[row + j];
            // apply Game‑of‑Life rules
            output[row + j] = (cell == 1) ?
                               ((sum < 2 || sum > 3) ? 0 : 1) :
                               (sum == 3 ? 1 : 0);
        }
    }
}
