#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    std::size_t row, column;
    double value;
};

/*
 * Compute y = alpha*A*x + beta*y where alpha and beta are scalars,
 * x and y are vectors, and A is a sparse matrix stored in COO format.
 * x and y are length N and A is M x N.
 *
 * The implementation uses OpenMP to parallelise the outer loop over
 * the non‑zero entries of A. A per‑thread buffer is used to avoid
 * atomic updates on the shared output vector y.
 *
 * The algorithm is equivalent to the reference implementation:
 *   y = beta * y;
 *   for each (i,j,v) in A:
 *       if i < M && j < N:
 *           y[i] += alpha * v * x[j];
 */
void spmv(double alpha,
          const std::vector<COOElement>& A,
          const std::vector<double>& x,
          double beta,
          std::vector<double>& y,
          std::size_t M,
          std::size_t N)
{
    /* Scale the destination vector by beta. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i)
        y[i] *= beta;

    /* Determine the number of threads and create per‑thread buffers. */
    const int nthreads = omp_get_max_threads();
    std::vector<std::vector<double>> local(nthreads, std::vector<double>(M, 0.0));

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::vector<double>& x_local = x;          // read‑only reference
        std::vector<double>& y_local = local[tid];       // local buffer

        /* Accumulate contributions from each non‑zero element. */
        #pragma omp for schedule(static)
        for (std::size_t idx = 0; idx < A.size(); ++idx)
        {
            const COOElement& e = A[idx];
            if (e.row < M && e.column < N)
            {
                y_local[e.row] += alpha * e.value * x_local[e.column];
            }
        }
    }

    /* Merge per‑thread buffers into the global output vector. */
    for (int t = 0; t < nthreads; ++t)
    {
        const std::vector<double>& y_local = local[t];
        for (std::size_t i = 0; i < M; ++i)
            y[i] += y_local[i];
    }
}
