inline void partialMinimums(std::vector<float> &x) {
    const std::size_t n = x.size();
    if (n == 0) return;

    // Rough block size – tune this for best performance on the target CPU.
    constexpr std::size_t BLOCK = 512;
    const std::size_t blocks = (n + BLOCK - 1) / BLOCK;

    // First pass: compute inclusive minima for each block independently
    // and store the minimal value of each block.
    std::vector<float> block_min(blocks);

    #pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < blocks; ++b) {
        const std::size_t start = b * BLOCK;
        const std::size_t end   = std::min(start + BLOCK, n);

        float cur_min = std::numeric_limits<float>::max();
        for (std::size_t i = start; i < end; ++i) {
            cur_min = std::min(cur_min, x[i]);
            x[i] = cur_min;                       // inclusive prefix within block
        }
        block_min[b] = cur_min;                    // minimal element of this block
    }

    // Second pass: propagate block minima across blocks.
    // `prev_min` holds the minimal value seen so far from preceding blocks.
    float prev_min = block_min[0];
    for (std::size_t b = 1; b < blocks; ++b) {
        const std::size_t start = b * BLOCK;
        const std::size_t end   = std::min(start + BLOCK, n);

        // All values inside this block already represent the inclusive min of the block itself.
        // If the smallest value from previous blocks (`prev_min`) is smaller than the block's min,
        // we need to adjust each element accordingly.
        if (prev_min < block_min[b]) {
            for (std::size_t i = start; i < end; ++i) {
                if (x[i] > prev_min) x[i] = prev_min;
            }
        }

        prev_min = std::min(prev_min, block_min[b]);   // update global minimal value
    }
}
