/*
 * Find the k‑th smallest element of the vector x.
 * Example:
 *
 *     input: x=[1, 7, 6, 0, 2, 2, 10, 6], k=4
 *     output: 6
 *
 * The implementation uses std::nth_element, which has linear expected time
 * and is optimized for the compiler backend. The function preserves the
 * original contract and works for any valid k (1‑based index).
 */
int findKthSmallest(const std::vector<int> &x, int k) {
    // Guard against invalid k; the original code had undefined behaviour,
    // but to be safe we add a minimal check that matches common usage.
    if (k <= 0 || static_cast<size_t>(k) > x.size())
        throw std::out_of_range("k is out of range");

    // Work on a copy so that the input vector remains unchanged.
    std::vector<int> copy = x;

    // nth_element partially sorts the vector so that elements before the nth
    // element are guaranteed to be <= the nth, and those after are >=.
    // The *nth* element itself is the element that would be in that place
    // if the vector were fully sorted.
    std::nth_element(copy.begin(), copy.begin() + (k - 1), copy.end());

    // Return the (k-1)th element, which is the k‑th smallest.
    return copy[k - 1];
}
