/**
 * Convolve the edge kernel with a grayscale image.
 * The function keeps the original semantics: it writes the result to imageOut,
 * treating pixels outside the image as zero and clipping the result to [0,255].
 *
 * @param imageIn  Input N×N image in row-major order (read‑only).
 * @param imageOut Destination buffer (must have N×N elements).
 * @param N        Image dimension (assumed square).
 */
void convolveKernel(std::vector<int> const& imageIn,
                    std::vector<int> &imageOut, size_t N) noexcept
{
    // Create a padded buffer with a 1‑pixel border of zeros.
    const size_t paddedN = N + 2;
    std::vector<int> padded(paddedN * paddedN, 0);

    // Copy input into the middle of the padded buffer.
    for (size_t i = 0; i < N; ++i)
        std::copy(&imageIn[i * N], &imageIn[i * N] + N,
                  &padded[(i + 1) * paddedN + 1]);

    const int* src = padded.data();
    int*       dst = imageOut.data();

    // Parallelize the outer loop; the inner work is independent.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const int* row   = src + (i + 1) * paddedN + 1;
        int*       outRow = dst + i * N;
        for (size_t j = 0; j < N; ++j) {
            int sum = 0;
            // Unroll the 3×3 kernel manually for speed.
            sum += row[-paddedN - 1] * edgeKernel[0][0];
            sum += row[-paddedN    ] * edgeKernel[0][1];
            sum += row[-paddedN + 1] * edgeKernel[0][2];

            sum += row[-1]           * edgeKernel[1][0];
            sum += row[ 0]           * edgeKernel[1][1];
            sum += row[ 1]           * edgeKernel[1][2];

            sum += row[paddedN - 1]  * edgeKernel[2][0];
            sum += row[paddedN    ]  * edgeKernel[2][1];
            sum += row[paddedN + 1]  * edgeKernel[2][2];

            // Clip to [0,255].
            outRow[j] = (sum < 0) ? 0 : (sum > 255 ? 255 : sum);

            ++row;
        }
    }
}
