        double local_diff = best_diff;

        #pragma omp for nowait
        for (std::size_t i = 1; i < x.size(); ++i) {
            double d = std::abs(x[i] - pi);
            if (d < local_diff) {
                local_diff = d;
                local_index = i;
            }
        }

        #pragma omp critical
        {
            if (local_diff < best_diff) {
                best_diff = local_diff;
                best_index = local_index;
            }
        }
    }
#else
    for (std::size_t i = 1; i < x.size(); ++i) {
        double d = std::abs(x[i] - pi);
        if (d < best_diff) {
            best_diff = d;
            best_index = i;
        }
    }
#endif

    return best_index;
}
