#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <limits>

struct Point { 
    double x, y; 
};

/* Computes the Euclidean distance between two points. */
inline double dist(const Point& a, const Point& b) {
    double dx = a.x - b.x, dy = a.y - b.y;
    return std::sqrt(dx*dx + dy*dy);
}

/* Helper to compute squared distance; no sqrt needed. */
inline double sqdist(const Point& a, const Point& b) {
    double dx = a.x - b.x, dy = a.y - b.y;
    return dx*dx + dy*dy;
}

/* Divide & conquer algorithm to find the squared distance
   between the closest pair of points in pointsSortedByX. */
static double closest_pair_rec(
    std::vector<Point>& pts,
    std::vector<Point>& aux,
    int left,
    int right)          // [left, right)
{
    int n = right - left;
    if (n <= 3) {
        double minSq = std::numeric_limits<double>::infinity();
        for (int i = left; i < right; ++i)
            for (int j = i + 1; j < right; ++j)
                minSq = std::min(minSq, sqdist(pts[i], pts[j]));
        // sort by y for small segments
        std::sort(pts.begin() + left, pts.begin() + right,
                  [](const Point& a, const Point& b){ return a.y < b.y; });
        return minSq;
    }

    int mid = left + n / 2;
    double midx = pts[mid].x;

    double d = std::min(closest_pair_rec(pts, aux, left, mid),
                        closest_pair_rec(pts, aux, mid, right));

    /* Merge step: merge by y into aux */
    std::merge(pts.begin() + left, pts.begin() + mid,
               pts.begin() + mid, pts.begin() + right,
               aux.begin(), [](const Point& a, const Point& b){ return a.y < b.y; });
    std::copy(aux.begin(), aux.begin() + n, pts.begin() + left);

    /* Build strip of points within sqrt(d) of mid line */
    std::vector<Point> strip;
    double distLimit = std::sqrt(d);
    for (int i = left; i < right; ++i)
        if (std::abs(pts[i].x - midx) <= distLimit)
            strip.push_back(pts[i]);

    /* Check at most 7 neighbors per point in strip */
    for (size_t i = 0; i < strip.size(); ++i) {
        for (size_t j = i + 1;
             j < strip.size() && (strip[j].y - strip[i].y) <= distLimit;
             ++j) {
            d = std::min(d, sqdist(strip[i], strip[j]));
            distLimit = std::sqrt(d);
        }
    }
    return d;
}

/* Return the distance between the closest two points in the vector points.
   The function preserves the exact behavior of the original implementation
   but runs in O(n log n) time. */
double closestPair(std::vector<Point> const& points) {
    size_t n = points.size();
    if (n < 2) return 0.0;

    std::vector<Point> pts = points;               // make a modifiable copy
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b){ return a.x < b.x; });

    std::vector<Point> aux(n);
    double minSq = closest_pair_rec(pts, aux, 0, n);
    return std::sqrt(minSq);
}
