/* Return the index of the first even number in the vector x.
   Examples:
   input: [7, 3, 9, 5, 5, 7, 2, 9, 12, 11]
   output: 6
   input: [3, 8, 9, 9, 3, 4, 8, 6]
   output: 1
*/
size_t findFirstEven(const std::vector<int>& x) {
    const size_t n = x.size();
    const int* restrict beg = x.data();
    const int* restrict end = beg + n;

    // Fast branch‑and‑bound: try to find a match in chunks of 8 ints.
    const int* p = beg;
    size_t i = 0;
    for (; p + 8 <= end; p += 8, i += 8) {
        // unrolled SIMD‑style checks – the compiler will vectorise.
        if ((p[0] & 1) == 0) return i + 0;
        if ((p[1] & 1) == 0) return i + 1;
        if ((p[2] & 1) == 0) return i + 2;
        if ((p[3] & 1) == 0) return i + 3;
        if ((p[4] & 1) == 0) return i + 4;
        if ((p[5] & 1) == 0) return i + 5;
        if ((p[6] & 1) == 0) return i + 6;
        if ((p[7] & 1) == 0) return i + 7;
    }

    // Handle the remaining elements
    for (; p < end; ++p, ++i) {
        if ((*p & 1) == 0) return i;
    }
    return n;   // no even element found
}
