#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

/* Return true if the vector `x` contains the value `target`. 
   The implementation uses a raw-pointer loop and, if available,
   an OpenMP parallel reduction to speed up the search on multi‑core machines.
   The behaviour is identical to std::find.
*/
bool contains(const std::vector<int> &x, int target) noexcept {
    // Empty vector – immediately return false
    if (x.empty()) return false;

    // Use a raw pointer for fast iteration
    const int *data = x.data();
    const std::size_t n   = x.size();
    const std::size_t step = 4;                   // unroll factor
    bool found = false;

    #pragma omp parallel for reduction(||:found) schedule(static)
    for (std::size_t i = 0; i + step <= n; i += step) {
        // Unrolled loop – four comparisons per iteration
        if (data[i]     == target) { found = true; continue; }
        if (data[i + 1] == target) { found = true; continue; }
        if (data[i + 2] == target) { found = true; continue; }
        if (data[i + 3] == target) { found = true; continue; }
    }

    // Handle the remaining elements (n % 4)
    if (!found) {
        for (std::size_t i = n - (n % step); i < n; ++i) {
            if (data[i] == target) { found = true; break; }
        }
    }

    return found;
}
