/*
   Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither.
   Examples:
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=7
   output: true
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=1
   output: false
*/
inline bool xorContains(std::vector<int> const& x,
                        std::vector<int> const& y,
                        int val) noexcept
{
    // Choose the smaller vector to build a hash set for the
    // fastest membership test.  The overall complexity stays O(n).
    if (x.size() <= y.size()) {
        std::unordered_set<int> inX;
        inX.reserve(x.size()*2);
        for (int v : x) inX.insert(v);

        bool foundInX = inX.find(val) != inX.end();
        bool foundInY = std::find(y.begin(), y.end(), val) != y.end();
        return foundInX ^ foundInY;
    } else {
        std::unordered_set<int> inY;
        inY.reserve(y.size()*2);
        for (int v : y) inY.insert(v);

        bool foundInY = inY.find(val) != inY.end();
        bool foundInX = std::find(x.begin(), x.end(), val) != x.end();
        return foundInX ^ foundInY;
    }
}
