#pragma once
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

/*
 * Matrix‑by‑matrix multiplication (C = A * B).
 * Rows of A are length K, rows of B are length N.
 * Result C has dimensions M × N, all matrices stored in row‑major order.
 *
 * Implementation: blocked algorithm with OpenMP parallelism and loop unrolling
 * that maximises cache utilisation and takes advantage of SIMD on modern CPUs.
 * The full behaviour (including accumulation into C) is preserved.
 */
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double>       &C,
                 std::size_t                M,
                 std::size_t                K,
                 std::size_t                N)
{
    /* Block size (in elements). 64 gives a good trade‑off for L1 cache (32 bytes / 8). */
    constexpr std::size_t BS = 64;

    /* Ensure C is zero‑initialised before accumulation. */
    std::fill(C.begin(), C.end(), 0.0);

    /* Parallelise over outer loop i using OpenMP. */
    #pragma omp parallel for schedule(static)
    for (std::size_t ii = 0; ii < M; ii += BS)
    {
        const std::size_t i_end = std::min(ii + BS, M);
        for (std::size_t kk = 0; kk < K; kk += BS)
        {
            const std::size_t k_end = std::min(kk + BS, K);
            /* Process the sub‑panel (i,j,k).  The j loop is left unblocked
               because the inner product is already cache‑friendly. */
            for (std::size_t i = ii; i < i_end; ++i)
            {
                const double* a_row = &A[i * K];
                double*       c_row = &C[i * N];
                for (std::size_t k = kk; k < k_end; ++k)
                {
                    const double aik = a_row[k];
                    if (aik == 0.0) continue;          // cheap skip for sparsity
                    const double* b_row = &B[k * N];
                    /* Unroll inner j loop for better pipeline utilisation. */
                    std::size_t j = 0;
                    for (; j + 7 < N; j += 8)
                    {
                        c_row[j]     += aik * b_row[j];
                        c_row[j + 1] += aik * b_row[j + 1];
                        c_row[j + 2] += aik * b_row[j + 2];
                        c_row[j + 3] += aik * b_row[j + 3];
                        c_row[j + 4] += aik * b_row[j + 4];
                        c_row[j + 5] += aik * b_row[j + 5];
                        c_row[j + 6] += aik * b_row[j + 6];
                        c_row[j + 7] += aik * b_row[j + 7];
                    }
                    for (; j < N; ++j)
                        c_row[j] += aik * b_row[j];
                }
            }
        }
    }
}
