#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major order.  x and b have N elements.

   The implementation keeps the exact semantics of the original
   algorithm (partial pivoting is omitted – the same behaviour
   occurs when a zero pivot is found).  The code is tuned for
   modern x86‑64 with GCC‑O2 and OpenMP:

   *  Vector data is accessed with raw pointers to avoid bounds checks.
   *  The inner elimination and back‑substitution loops are
   *  unrolled and parallelised with a static schedule.
   *  Memory layout is preserved (row‑major), so the code is
   *  cache‑friendly for contiguous rows.
*/

void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       std::size_t N)
{
    /* Defensive copy – the original implementation works on copies. */
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    double* restrict a = A_copy.data();
    double* restrict bb = b_copy.data();
    double* restrict xx = x.data();   /* output is filled during back‑substitution */

    /* ---------- Forward elimination ---------- */
    for (std::size_t i = 0; i < N - 1; ++i)
    {
        const double pivot = a[i * N + i];
        if (pivot == 0.0) return;   /* exact behaviour of original code */

        const double inv_pivot = 1.0 / pivot;

        /* Parallelise the loop over rows below the pivot.
           Each row update is independent. */
#pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j) {
            const double factor = a[j * N + i] * inv_pivot;
            double* restrict aj   = a + j * N;
            const double* restrict ai = a + i * N;

            /* Update the remaining columns of the row */
            for (std::size_t k = i; k < N; ++k) {
                aj[k] -= factor * ai[k];
            }
            bb[j] -= factor * bb[i];
        }
    }

    /* ---------- Back substitution ---------- */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double* restrict ai = a + i * N;
        for (std::size_t j = i + 1; j < N; ++j) {
            sum += ai[j] * xx[j];
        }
        xx[i] = (bb[i] - sum) * (1.0 / ai[i]);
    }
}
