#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

struct Result {
   int startTime, duration;
   float value;
};

/* Parallel merge sort on CPU.
   It sorts the passed vector by startTime in ascending order.
   The implementation works best on large vectors – for small sizes it falls back
   to the single‑threaded std::sort.  The function keeps the exact behaviour
   (stable ordering for equal startTimes is *not* required in the original code,
   hence an ordinary merge sort is sufficient). */
static void parallel_merge_sort(std::vector<Result>& v, std::size_t left, std::size_t right, std::vector<Result>& temp, int depth = 0)
{
    // For tiny ranges use insertion sort for speed
    if (right - left <= 16) {
        std::sort(v.begin() + left, v.begin() + right,
                  [](const Result& a, const Result& b) { return a.startTime < b.startTime; });
        return;
    }

    std::size_t mid = left + (right - left) / 2;

    // Limit recursion parallelism to available threads
    if (depth < omp_get_max_threads()) {
#pragma omp task shared(v, temp) if (depth < omp_get_max_threads() - 1)
        parallel_merge_sort(v, left, mid, temp, depth + 1);
#pragma omp task shared(v, temp) if (depth < omp_get_max_threads() - 1)
        parallel_merge_sort(v, mid, right, temp, depth + 1);
#pragma omp taskwait
    } else {
        parallel_merge_sort(v, left, mid, temp, depth + 1);
        parallel_merge_sort(v, mid, right, temp, depth + 1);
    }

    // Merge sorted halves
    std::size_t i = left, j = mid, k = left;
    while (i < mid && j < right)
        temp[k++] = (v[i].startTime <= v[j].startTime) ? v[i++] : v[j++];
    while (i < mid) temp[k++] = v[i++];
    while (j < right) temp[k++] = v[j++];

    // Copy back
    std::copy(temp.begin() + left, temp.begin() + right, v.begin() + left);
}

void sortByStartTime(std::vector<Result> &results)
{
    if (results.size() <= 1) return;
#pragma omp parallel
    {
#pragma omp single nowait
        {
            std::vector<Result> temp(results.size());
            parallel_merge_sort(results, 0, results.size(), temp, 0);
        }
    }
}
