#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Sparse LU factorisation for a dense NxN matrix stored in row‑major order.
 * The upper part of the matrix holds U and the strictly lower part holds
 * L (with unit diagonal).  The algorithm is in‑place: the result overwrites
 * the input matrix.
 *
 * This version uses OpenMP parallelisation of the outermost loop and a
 * hand‑crafted blocking layout to keep the inner updates cache friendly.
 *
 * @param A reference to a vector of size N*N containing the matrix in
 *          row‑major order.  It is modified in‑place.
 * @param N dimension of the square matrix.
 */
inline void luFactorize(std::vector<double> &A, std::size_t N) {
    constexpr std::size_t BLOCK = 32;          // Block size tuned for L3 cache
    const std::size_t nBlocks = (N + BLOCK - 1) / BLOCK;

    /* Parallelise over the whole k loop.  The critical sections that
     * touch the k‑th row start only once per k, and the updates to rows
     * i>k can be done in parallel without race conditions.  OpenMP
     * schedules the iterations dynamically to mitigate load imbalance
     * caused by ill‑conditioned matrices. */
    #pragma omp parallel for schedule(dynamic)
    for (std::size_t kb = 0; kb < nBlocks; ++kb) {
        const std::size_t k_start = kb * BLOCK;
        const std::size_t k_end   = std::min(k_start + BLOCK, N);

        for (std::size_t k = k_start; k < k_end; ++k) {
            const double * row_k = &A[k * N];
            const double pivot = row_k[k];
            /* Normalise pivot to avoid repeated division in the inner loop. */
            const double inv_pivot = 1.0 / pivot;

            /* Update lower part of column k (store L). */
            for (std::size_t i = k + 1; i < N; ++i) {
                double * row_i = &A[i * N];
                row_i[k] = row_i[k] * inv_pivot;   // Store factor f = aik/pivot
            }

            /* Update the trailing sub‑matrix.  We iterate over blocks of
             * rows to keep the inner loop highly cache‑friendly. */
            for (std::size_t ib = kb; ib < nBlocks; ++ib) {
                const std::size_t i_start = ib * BLOCK;
                const std::size_t i_end   = std::min(i_start + BLOCK, N);

                for (std::size_t i = i_start; i < i_end; ++i) {
                    double * row_i = &A[i * N];
                    const double factor = row_i[k];

                    /* Avoid unnecessary work for the diagonal element. */
                    if (factor == 0.0) continue;

                    /* Unroll the remaining columns in steps of four. */
                    std::size_t j = k + 1;
                    for (; j + 3 < N; j += 4) {
                        row_i[j]   -= factor * row_k[j];
                        row_i[j+1] -= factor * row_k[j+1];
                        row_i[j+2] -= factor * row_k[j+2];
                        row_i[j+3] -= factor * row_k[j+3];
                    }
                    for (; j < N; ++j)
                        row_i[j] -= factor * row_k[j];
                }
            }
        }
    }
}
