05_fft_inverse_fft:
```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/*============================================================
   In‑place Fast Fourier Transform (radix‑2 Cooley‑Tukey)
   The function assumes that x.size() is a power of two.
   Correctness is identical to the original implementation,
   but performance is improved through
      • pre‑computed twiddle factors,
      • explicit bit‑reverse permutation table,
      • OpenMP parallelisation of independent butterfly stages.
============================================================*/
inline void fft_inplace(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));

    /*--- 1. Bit‑reverse the input once -----------------------------------*/
    static std::vector<std::size_t> rev;          // dynamic size 0..n
    if (rev.size() != N) {
        rev.resize(N);
        for (std::size_t i = 0; i < N; ++i) {
            std::size_t j = i;
            j = ((j & 0xaaaaaaaaaaaaaaaaULL) >> 1) |
                ((j & 0x5555555555555555ULL) << 1);
            j = ((j & 0xccccccccccccccccULL) >> 2) |
                ((j & 0x3333333333333333ULL) << 2);
            j = ((j & 0xf0f0f0f0f0f0f0f0ULL) >> 4) |
                ((j & 0x0f0f0f0f0f0f0f0fULL) << 4);
            j = ((j & 0xff00ff00ff00ff00ULL) >> 8) |
                ((j & 0x00ff00ff00ff00ffULL) << 8);
            j = ((j & 0xffff0000ffff0000ULL) >> 16) |
                ((j & 0x0000ffff0000ffffULL) << 16);
            j >>= (64 - logN);
            rev[i] = j;
        }
    }

    for (std::size_t i = 0; i < N; ++i)
        if (rev[i] > i)
            std::swap(x[i], x[rev[i]]);

    /*--- 2. Pre‑compute twiddle factors for each stage -------------------*/
    std::vector<std::vector<std::complex<double>>> twiddles(logN);
    for (std::size_t s = 0; s < logN; ++s) {
        std::size_t m = 1u << (s + 1);          // stage length
        twiddles[s].resize(m / 2);
        const double theta = -2.0 * M_PI / static_cast<double>(m);
        for (std::size_t j = 0; j < m / 2; ++j)
            twiddles[s][j] = std::complex<double>(std::cos(theta * j),
                                                   std::sin(theta * j));
    }

    /*--- 3. Main FFT loops (paralleled by OpenMP) -----------------------*/
#pragma omp parallel
    {
        for (std::size_t s = 0; s < logN; ++s) {
            const std::size_t m   = 1u << (s + 1);
            const std::size_t mh  = m >> 1;
#pragma omp for schedule(static)
            for (std::size_t k = 0; k < N; k += m) {
                for (std::size_t j = 0; j < mh; ++j) {
                    const std::complex<double> t = twiddles[s][j] * x[k + j + mh];
                    x[k + j + mh] = x[k + j] - t;
                    x[k + j]     += t;
                }
            }
        }
    }
}

/*============================================================
   Forward FFT helper – simply forwards to the in‑place FFT.
============================================================*/
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    fft_inplace(x);
}

/*============================================================
   Inverse FFT – exact duplicate of the original logic
============================================================*/
inline void ifft(std::vector<std::complex<double>>& x)
{
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    fft_helper(x);

    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    const double invN = 1.0 / static_cast<double>(x.size());
    std::transform(x.begin(), x.end(), x.begin(),
                   [invN](std::complex<double> c){ return c * invN; });
}
